From the FreeBSD 9.3 source.  Note that the default format
is set to sha512, not des:

        /*
         * List of supported crypt(3) formats.  The first element in the list will
         * be the default.
         */
        static const struct crypt_format {
            const char *const name;
            char *(*const func)(const char *, const char *);
            const char *const magic;
        } crypt_formats[] = {
            /* default format */
            { "sha512", crypt_sha512,       "$6$"   },

            /* other supported formats */
            { "md5",    crypt_md5,      "$1$"   },
        #ifdef HAS_BLOWFISH
            { "blf",    crypt_blowfish,     "$2"    },
        #endif
            { "nth",    crypt_nthash,       "$3$"   },
            { "sha256", crypt_sha256,       "$5$"   },
        #ifdef HAS_DES
            { "des",    crypt_des,      "_" },
        #endif

            },
        #endif



            /* sentinel */
            { NULL,     NULL,           NULL    }
        };


